(function(window2, document2) {
  var myImage = (function() {
    var imgNode = document2.createElement("img");
    document2.body.appendChild(imgNode);
    return function(src) {
      imgNode.src = src;
    };
  })();
  var proxyImage = (function() {
    var image = new Image();
    image.onload = function() {
      myImage(this.src);
    };
    return function(src) {
      myImage("E:/demo/liaolongdong.github.io/assets/img/profile.png");
      image.src = src;
    };
  })();
  proxyImage("https://pic1.zhimg.com/v2-0391689010c83495ba3923cd04c71206_1200x500.jpg");
})(window, document);
